content.text:
1	{
2	  "openapi": "3.0.3",
3	  "info": {
4	    "title": "CineRide Media Operations Platform API",
5	    "version": "1.0.0",
6	    "description": "REST API for the CineRide offline-first media operations platform. Manages movies, editorial content, ride requests, environmental sensors, and a local funds ledger."
7	  },
8	  "servers": [
9	    { "url": "/api", "description": "Local API (via Nginx reverse proxy)" }
10	  ],
11	  "components": {
12	    "securitySchemes": {
13	      "BearerAuth": {
14	        "type": "http",
15	        "scheme": "bearer",
16	        "bearerFormat": "JWT"
17	      },
18	      "ApiKeyAuth": {
19	        "type": "apiKey",
20	        "in": "header",
21	        "name": "X-API-Key"
22	      }
23	    },
24	    "schemas": {
25	      "User": {
26	        "type": "object",
27	        "properties": {
28	          "_id": { "type": "string" },
29	          "username": { "type": "string" },
30	          "role": { "type": "string", "enum": ["administrator", "editor", "reviewer", "dispatcher", "regular_user"] },
31	          "display_name": { "type": "string" },
32	          "phone": { "type": "string", "description": "Masked for non-admins: (415) ***-**21" },
33	          "status": { "type": "string", "enum": ["active", "inactive", "suspended"] }
34	        }
35	      },
36	      "Movie": {
37	        "type": "object",
38	        "properties": {
39	          "_id": { "type": "string" },
40	          "title": { "type": "string" },
41	          "description": { "type": "string" },
42	          "categories": { "type": "array", "items": { "type": "string" } },
43	          "tags": { "type": "array", "items": { "type": "string" } },
44	          "mpaa_rating": { "type": "string", "enum": ["G", "PG", "PG-13", "R", "NC-17", "NR"] },
45	          "release_date": { "type": "string", "format": "date" },
46	          "poster": { "type": "object" },
47	          "stills": { "type": "array" },
48	          "is_published": { "type": "boolean" },
49	          "popularity_score": { "type": "number" }
50	        }
51	      },
52	      "ContentItem": {
53	        "type": "object",
54	        "properties": {
55	          "_id": { "type": "string" },
56	          "content_type": { "type": "string", "enum": ["article", "gallery", "video", "event"] },
57	          "title": { "type": "string" },
58	          "body": { "type": "string" },
59	          "status": { "type": "string", "enum": ["draft", "in_review_1", "in_review_2", "scheduled", "published", "unpublished"] },
60	          "author": { "type": "object" },
61	          "scheduled_publish_date": { "type": "string", "format": "date-time" }
62	        }
63	      },
64	      "RideRequest": {
65	        "type": "object",
66	        "properties": {
67	          "_id": { "type": "string" },
68	          "requester": { "type": "object" },
69	          "pickup_text": { "type": "string" },
70	          "dropoff_text": { "type": "string" },
71	          "rider_count": { "type": "integer", "minimum": 1, "maximum": 6 },
72	          "time_window_start": { "type": "string", "format": "date-time" },
73	          "time_window_end": { "type": "string", "format": "date-time" },
74	          "vehicle_type": { "type": "string", "enum": ["sedan", "suv", "van", "shuttle"] },
75	          "status": { "type": "string", "enum": ["pending_match", "accepted", "in_progress", "completed", "canceled", "in_dispute"] },
76	          "state_transitions": { "type": "array" }
77	        }
78	      },
79	      "LedgerEntry": {
80	        "type": "object",
81	        "properties": {
82	          "_id": { "type": "string" },
83	          "amount": { "type": "number" },
84	          "payment_method": { "type": "string", "enum": ["cash", "card_on_file"] },
85	          "receipt_number": { "type": "string" },
86	          "idempotency_key": { "type": "string" },
87	          "status": { "type": "string", "enum": ["pending", "posted", "failed", "reconciled"] },
88	          "ledger_date": { "type": "string" },
89	          "day_closed": { "type": "boolean" }
90	        }
91	      },
92	      "SensorReading": {
93	        "type": "object",
94	        "properties": {
95	          "device_id": { "type": "string" },
96	          "timestamp": { "type": "string", "format": "date-time" },
97	          "value": { "type": "number" },
98	          "unit": { "type": "string" },
99	          "is_raw": { "type": "boolean" },
100	          "is_cleaned": { "type": "boolean" },
101	          "outlier_flags": { "type": "object" }
102	        }
103	      },
104	      "Error": {
105	        "type": "object",
106	        "properties": {
107	          "code": { "type": "string" },
108	          "message": { "type": "string" },
109	          "details": { "type": "array" }
110	        }
111	      }
112	    }
113	  },
114	  "paths": {
115	    "/health": {
116	      "get": {
117	        "summary": "Health check",
118	        "tags": ["System"],
119	        "responses": { "200": { "description": "Service is healthy" } }
120	      }
121	    },
122	    "/auth/login": {
123	      "post": {
124	        "summary": "Login with username and password",
125	        "tags": ["Auth"],
126	        "requestBody": {
127	          "required": true,
128	          "content": { "application/json": { "schema": { "type": "object", "properties": { "username": { "type": "string" }, "password": { "type": "string" } }, "required": ["username", "password"] } } }
129	        },
130	        "responses": { "200": { "description": "JWT token and user info" }, "401": { "description": "Invalid credentials" } }
131	      }
132	    },
133	    "/auth/logout": {
134	      "post": { "summary": "Logout and revoke current session", "tags": ["Auth"], "security": [{ "BearerAuth": [] }], "responses": { "200": { "description": "Logged out" } } }
135	    },
136	    "/auth/me": {
137	      "get": { "summary": "Get current user info", "tags": ["Auth"], "security": [{ "BearerAuth": [] }], "responses": { "200": { "description": "Current user" } } }
138	    },
139	    "/users": {
140	      "get": { "summary": "List users (admin only)", "tags": ["Users"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "page", "in": "query", "schema": { "type": "integer" } }, { "name": "role", "in": "query", "schema": { "type": "string" } }], "responses": { "200": { "description": "User list" } } },
141	      "post": { "summary": "Create user (admin only)", "tags": ["Users"], "security": [{ "BearerAuth": [] }], "responses": { "201": { "description": "User created" } } }
142	    },
143	    "/movies": {
144	      "get": { "summary": "List movies", "tags": ["Movies"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "category", "in": "query", "schema": { "type": "string" } }, { "name": "sort", "in": "query", "schema": { "type": "string", "enum": ["popularity", "rating", "newest", "title"] } }], "responses": { "200": { "description": "Movie list" } } },
145	      "post": { "summary": "Create movie (staff only)", "tags": ["Movies"], "security": [{ "BearerAuth": [] }], "responses": { "201": { "description": "Movie created" } } }
146	    },
147	    "/movies/{id}": {
148	      "get": { "summary": "Get movie by ID", "tags": ["Movies"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "id", "in": "path", "required": true, "schema": { "type": "string" } }], "responses": { "200": { "description": "Movie detail" } } },
149	      "put": { "summary": "Update movie (staff only)", "tags": ["Movies"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "id", "in": "path", "required": true, "schema": { "type": "string" } }], "responses": { "200": { "description": "Movie updated" } } }
150	    },
151	    "/movies/{id}/poster": {
152	      "post": { "summary": "Upload poster (JPG/PNG, max 10MB)", "tags": ["Movies"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "id", "in": "path", "required": true, "schema": { "type": "string" } }], "requestBody": { "content": { "multipart/form-data": { "schema": { "type": "object", "properties": { "poster": { "type": "string", "format": "binary" } } } } } }, "responses": { "200": { "description": "Poster uploaded" } } }
153	    },
154	    "/movies/{id}/unpublish": {
155	      "post": { "summary": "Unpublish a movie", "tags": ["Movies"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "id", "in": "path", "required": true, "schema": { "type": "string" } }], "responses": { "200": { "description": "Movie unpublished" } } }
156	    },
157	    "/movie-import/upload": {
158	      "post": { "summary": "Upload import file (JSON/CSV)", "tags": ["Movie Import"], "security": [{ "BearerAuth": [] }], "responses": { "201": { "description": "Import job created" } } }
159	    },
160	    "/movie-import/{jobId}/execute": {
161	      "post": { "summary": "Execute import after conflict resolution", "tags": ["Movie Import"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "jobId", "in": "path", "required": true, "schema": { "type": "string" } }], "responses": { "200": { "description": "Import executed" } } }
162	    },
163	    "/content": {
164	      "get": { "summary": "List content items", "tags": ["Content"], "security": [{ "BearerAuth": [] }], "responses": { "200": { "description": "Content list" } } },
165	      "post": { "summary": "Create content (staff only)", "tags": ["Content"], "security": [{ "BearerAuth": [] }], "responses": { "201": { "description": "Content created" } } }
166	    },
167	    "/content/{id}/submit": {
168	      "post": { "summary": "Submit content for review (triggers sensitive word scan)", "tags": ["Content"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "id", "in": "path", "required": true, "schema": { "type": "string" } }], "responses": { "200": { "description": "Submitted or warning returned" } } }
169	    },
170	    "/content-review/{id}/review": {
171	      "post": { "summary": "Review content (reviewer only, step 1 or 2)", "tags": ["Content Review"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "id", "in": "path", "required": true, "schema": { "type": "string" } }], "requestBody": { "content": { "application/json": { "schema": { "type": "object", "properties": { "decision": { "type": "string", "enum": ["approved", "rejected"] }, "rejection_reason": { "type": "string" } } } } } }, "responses": { "200": { "description": "Review recorded" } } }
172	    },
173	    "/rides": {
174	      "get": { "summary": "List ride requests", "tags": ["Rides"], "security": [{ "BearerAuth": [] }], "responses": { "200": { "description": "Ride list" } } },
175	      "post": { "summary": "Create ride request", "tags": ["Rides"], "security": [{ "BearerAuth": [] }], "requestBody": { "content": { "application/json": { "schema": { "type": "object", "properties": { "pickup_text": { "type": "string" }, "dropoff_text": { "type": "string" }, "rider_count": { "type": "integer", "minimum": 1, "maximum": 6 }, "time_window_start": { "type": "string", "format": "date-time" }, "time_window_end": { "type": "string", "format": "date-time" }, "vehicle_type": { "type": "string" } } } } } }, "responses": { "201": { "description": "Ride created" } } }
176	    },
177	    "/rides/{id}/cancel": {
178	      "post": { "summary": "Cancel ride (free within 5 min, otherwise requires dispatcher approval)", "tags": ["Rides"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "id", "in": "path", "required": true, "schema": { "type": "string" } }], "responses": { "200": { "description": "Canceled or approval required" } } }
179	    },
180	    "/dispatch/queue": {
181	      "get": { "summary": "Get dispatcher queue (pending rides)", "tags": ["Dispatch"], "security": [{ "BearerAuth": [] }], "responses": { "200": { "description": "Pending rides" } } }
182	    },
183	    "/dispatch/rides/{id}/accept": {
184	      "post": { "summary": "Accept/match a ride request", "tags": ["Dispatch"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "id", "in": "path", "required": true, "schema": { "type": "string" } }], "responses": { "200": { "description": "Ride accepted" } } }
185	    },
186	    "/dispatch/disputes/{id}/resolve": {
187	      "post": { "summary": "Resolve a dispute", "tags": ["Dispatch"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "id", "in": "path", "required": true, "schema": { "type": "string" } }], "responses": { "200": { "description": "Dispute resolved" } } }
188	    },
189	    "/disputes": {
190	      "post": { "summary": "Initiate a dispute (any role)", "tags": ["Disputes"], "security": [{ "BearerAuth": [] }], "responses": { "201": { "description": "Dispute created" } } }
191	    },
192	    "/search": {
193	      "get": { "summary": "Unified search across movies, content, users", "tags": ["Search"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "q", "in": "query", "required": true, "schema": { "type": "string" } }, { "name": "type", "in": "query", "schema": { "type": "string", "enum": ["movie", "content", "user"] } }, { "name": "sort", "in": "query", "schema": { "type": "string", "enum": ["popularity", "rating", "newest"] } }], "responses": { "200": { "description": "Search results" } } }
194	    },
195	    "/search/suggest": {
196	      "get": { "summary": "Get search suggestions (typo-tolerant)", "tags": ["Search"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "q", "in": "query", "required": true, "schema": { "type": "string" } }], "responses": { "200": { "description": "Suggestions" } } }
197	    },
198	    "/recommendations/movies": {
199	      "get": { "summary": "Get personalized movie recommendations", "tags": ["Recommendations"], "security": [{ "BearerAuth": [] }], "responses": { "200": { "description": "Movie recommendations" } } }
200	    },
201	    "/sensors/ingest": {
202	      "post": { "summary": "Ingest a single sensor reading", "tags": ["Sensors"], "description": "Requires X-Device-Id and X-Device-Secret headers. Body device_id must match authenticated device.", "parameters": [{ "name": "X-Device-Id", "in": "header", "required": true, "schema": { "type": "string" } }, { "name": "X-Device-Secret", "in": "header", "required": true, "schema": { "type": "string" } }], "requestBody": { "content": { "application/json": { "schema": { "type": "object", "properties": { "device_id": { "type": "string" }, "timestamp": { "type": "string", "format": "date-time" }, "value": { "type": "number" } } } } } }, "responses": { "201": { "description": "Reading ingested" }, "401": { "description": "Invalid device credentials" }, "403": { "description": "Body/header device_id mismatch" } } }
203	    },
204	    "/sensors/ingest/batch": {
205	      "post": { "summary": "Batch ingest sensor readings (resumable)", "tags": ["Sensors"], "description": "Requires X-Device-Id and X-Device-Secret headers. All readings must match authenticated device. Optional X-Batch-Session header for resumable transfer.", "parameters": [{ "name": "X-Device-Id", "in": "header", "required": true, "schema": { "type": "string" } }, { "name": "X-Device-Secret", "in": "header", "required": true, "schema": { "type": "string" } }, { "name": "X-Batch-Session", "in": "header", "schema": { "type": "string" } }], "responses": { "201": { "description": "Batch results with session_id for resume" }, "401": { "description": "Invalid device credentials" }, "403": { "description": "Batch contains mismatched device_id" } } }
206	    },
207	    "/sensors/devices": {
208	      "get": { "summary": "List sensor devices", "tags": ["Sensors"], "security": [{ "BearerAuth": [] }], "responses": { "200": { "description": "Device list" } } },
209	      "post": { "summary": "Register sensor device (admin only)", "tags": ["Sensors"], "security": [{ "BearerAuth": [] }], "responses": { "201": { "description": "Device created" } } }
210	    },
211	    "/ledger/entries": {
212	      "post": { "summary": "Record a payment (idempotent)", "tags": ["Ledger"], "security": [{ "BearerAuth": [] }], "requestBody": { "content": { "application/json": { "schema": { "type": "object", "properties": { "amount": { "type": "number" }, "payment_method": { "type": "string", "enum": ["cash", "card_on_file"] }, "receipt_number": { "type": "string" }, "idempotency_key": { "type": "string" } } } } } }, "responses": { "201": { "description": "Entry recorded" } } },
213	      "get": { "summary": "List ledger entries", "tags": ["Ledger"], "security": [{ "BearerAuth": [] }], "responses": { "200": { "description": "Entry list" } } }
214	    },
215	    "/ledger/reconciliation/{date}": {
216	      "get": { "summary": "Get reconciliation for a date", "tags": ["Ledger"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "date", "in": "path", "required": true, "schema": { "type": "string", "format": "date" } }], "responses": { "200": { "description": "Reconciliation record" } } }
217	    },
218	    "/ledger/reconciliation/{date}/close": {
219	      "post": { "summary": "Close day (makes records immutable)", "tags": ["Ledger"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "date", "in": "path", "required": true, "schema": { "type": "string", "format": "date" } }], "responses": { "200": { "description": "Day closed" } } }
220	    },
221	    "/config": {
222	      "get": { "summary": "List config entries (admin only)", "tags": ["Config"], "security": [{ "BearerAuth": [] }], "responses": { "200": { "description": "Config list" } } },
223	      "post": { "summary": "Create/update config entry", "tags": ["Config"], "security": [{ "BearerAuth": [] }], "responses": { "201": { "description": "Config saved" } } }
224	    },
225	    "/extensions/clients": {
226	      "post": { "summary": "Create extension API client (admin only)", "tags": ["Extensions"], "security": [{ "BearerAuth": [] }], "responses": { "201": { "description": "Client created with API key (shown once)" } } },
227	      "get": { "summary": "List extension clients", "tags": ["Extensions"], "security": [{ "BearerAuth": [] }], "responses": { "200": { "description": "Client list" } } }
228	    },
229	    "/extensions/movies": {
230	      "get": { "summary": "Read movies via extension API", "tags": ["Extensions"], "security": [{ "ApiKeyAuth": [] }], "responses": { "200": { "description": "Movies" } } }
231	    },
232	    "/auth/change-password": {
233	      "post": { "summary": "Change password (required for bootstrap accounts)", "tags": ["Auth"], "security": [{ "BearerAuth": [] }], "responses": { "200": { "description": "Password changed" }, "422": { "description": "Validation error" } } }
234	    },
235	    "/auth/sessions": {
236	      "get": { "summary": "List active sessions", "tags": ["Auth"], "security": [{ "BearerAuth": [] }], "responses": { "200": { "description": "Session list" } } }
237	    },
238	    "/auth/revoke-sessions": {
239	      "post": { "summary": "Revoke all other sessions", "tags": ["Auth"], "security": [{ "BearerAuth": [] }], "responses": { "200": { "description": "Sessions revoked" } } }
240	    },
241	    "/users/{id}": {
242	      "get": { "summary": "Get user by ID (admin)", "tags": ["Users"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "id", "in": "path", "required": true, "schema": { "type": "string" } }], "responses": { "200": { "description": "User detail" } } },
243	      "put": { "summary": "Update user (admin)", "tags": ["Users"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "id", "in": "path", "required": true, "schema": { "type": "string" } }], "responses": { "200": { "description": "User updated" } } },
244	      "delete": { "summary": "Delete user (admin)", "tags": ["Users"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "id", "in": "path", "required": true, "schema": { "type": "string" } }], "responses": { "200": { "description": "User deleted" } } }
245	    },
246	    "/movies/{id}/republish": {
247	      "post": { "summary": "Republish a movie (staff)", "tags": ["Movies"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "id", "in": "path", "required": true, "schema": { "type": "string" } }], "responses": { "200": { "description": "Movie republished" } } }
248	    },
249	    "/movies/{id}/stills": {
250	      "post": { "summary": "Upload stills (JPG/PNG, staff)", "tags": ["Movies"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "id", "in": "path", "required": true, "schema": { "type": "string" } }], "responses": { "200": { "description": "Stills uploaded" } } }
251	    },
252	    "/movies/{id}/revisions": {
253	      "get": { "summary": "Get movie revision history (staff)", "tags": ["Movies"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "id", "in": "path", "required": true, "schema": { "type": "string" } }], "responses": { "200": { "description": "Revision list" } } }
254	    },
255	    "/content/{id}": {
256	      "get": { "summary": "Get content item (published for non-editorial)", "tags": ["Content"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "id", "in": "path", "required": true, "schema": { "type": "string" } }], "responses": { "200": { "description": "Content detail" } } },
257	      "put": { "summary": "Update draft content (staff)", "tags": ["Content"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "id", "in": "path", "required": true, "schema": { "type": "string" } }], "responses": { "200": { "description": "Content updated" } } }
258	    },
259	    "/content/{id}/reviews": {
260	      "get": { "summary": "Get content review history (editorial)", "tags": ["Content Review"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "id", "in": "path", "required": true, "schema": { "type": "string" } }], "responses": { "200": { "description": "Review history" } } }
261	    },
262	    "/content/{id}/unpublish": {
263	      "post": { "summary": "Unpublish content (staff)", "tags": ["Content"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "id", "in": "path", "required": true, "schema": { "type": "string" } }], "responses": { "200": { "description": "Content unpublished" } } }
264	    },
265	    "/rides/{id}": {
266	      "get": { "summary": "Get ride detail (own rides for users, all for dispatch)", "tags": ["Rides"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "id", "in": "path", "required": true, "schema": { "type": "string" } }], "responses": { "200": { "description": "Ride detail" } } }
267	    },
268	    "/rides/{id}/feedback": {
269	      "post": { "summary": "Submit ride feedback (requester only, completed rides)", "tags": ["Rides"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "id", "in": "path", "required": true, "schema": { "type": "string" } }], "responses": { "200": { "description": "Feedback submitted" } } }
270	    },
271	    "/dispatch/rides/{id}/transition": {
272	      "post": { "summary": "Transition ride status (dispatcher)", "tags": ["Dispatch"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "id", "in": "path", "required": true, "schema": { "type": "string" } }], "responses": { "200": { "description": "Ride transitioned" } } }
273	    },
274	    "/dispatch/rides/{id}/approve-cancel": {
275	      "post": { "summary": "Approve ride cancellation (dispatcher)", "tags": ["Dispatch"], "security": [{ "BearerAuth": [] }], "parameters": [{ "name": "id", "in": "path", "required": true, "schema": { "type": "string" } }], "responses": { "200": { "description": "Cancellation approved" } } }
276	    },
277	    "/dispatch/disputes": {
278	      "get": { "summary": "List disputes (dispatcher)", "tags": ["Dispatch"], "security": [{ "BearerAuth": [] }], "responses": { "200": { "description": "Dispute list" } } }
