20	  // Mongoose validation errors
21	  if (err.name === 'ValidationError') {
22	    const details = Object.values(err.errors).map(e => ({
23	      field: e.path,
24	      message: e.message
25	    }));
26	    return res.status(422).json({
27	      code: 'VALIDATION_ERROR',
28	      message: 'Validation failed',
29	      details
30	    });
31	  }
32	
33	  // Mongoose duplicate key errors
34	  if (err.code === 11000) {
35	    const field = Object.keys(err.keyValue || {})[0] || 'field';
36	    return res.status(409).json({
37	      code: 'DUPLICATE',
38	      message: `Duplicate value for ${field}`
39	    });
