23	    if (await bcrypt.compare(apiKey, client.api_key_hash)) {
24	      matchedClient = client;
25	      break;
26	    }
27	  }
28	
29	  if (!matchedClient) {
30	    return res.status(401).json({ code: 'UNAUTHORIZED', message: 'Invalid API key' });
31	  }
32	
33	  // Rate limiting
34	  const clientId = matchedClient._id.toString();
35	  const now = Date.now();
36	  const windowStart = now - 60000;
37	  const requests = rateLimitMap.get(clientId) || [];
38	  const recentRequests = requests.filter(t => t > windowStart);
39	
40	  if (recentRequests.length >= matchedClient.rate_limit) {
41	    return res.status(429).json({ code: 'RATE_LIMITED', message: 'Rate limit exceeded' });
