17	async function attemptPosting(entry) {
18	  try {
19	    // Validate: no duplicate receipt_number for the same ledger_date (besides this entry)
20	    const dupReceipt = await LedgerEntry.findOne({
21	      receipt_number: entry.receipt_number,
22	      ledger_date: entry.ledger_date,
23	      _id: { $ne: entry._id },
24	      status: { $in: ['posted', 'reconciled'] },
25	      deleted_at: null
26	    });
27	    if (dupReceipt) {
28	      throw new Error(`Duplicate receipt number '${entry.receipt_number}' for ${entry.ledger_date}`);
29	    }
30	
31	    entry.status = 'posted';
32	    await entry.save();
33	    return { entry, error: null };
34	  } catch (err) {
35	    entry.status = 'failed';
36	    entry.last_retry_at = new Date();
37	    await entry.save();
38	    return { entry, error: err.message };
39	  }
40	}
