176	  const totalCash = entries.filter(e => e.payment_method === 'cash').reduce((sum, e) => sum + e.amount, 0);
177	  const totalCard = entries.filter(e => e.payment_method === 'card_on_file').reduce((sum, e) => sum + e.amount, 0);
