203	async function retryFailedEntries() {
204	  const maxRetries = await getConfig('ledger_max_retries', 3);
205	  const entries = await LedgerEntry.find({
206	    status: 'failed',
207	    retry_count: { $lt: maxRetries },
208	    day_closed: false,
209	    deleted_at: null
210	  });
211	
212	  let retried = 0;
213	  for (const entry of entries) {
214	    // Exponential backoff: 1s, 4s, 16s
215	    const backoffMs = Math.pow(4, entry.retry_count) * 1000;
216	    const lastAttempt = entry.last_retry_at || entry.created_at;
217	    const nextRetryAfter = new Date(lastAttempt.getTime() + backoffMs);
218	
219	    if (new Date() < nextRetryAfter) continue;
220	
221	    entry.retry_count += 1;
222	
223	    try {
224	      const result = await attemptPosting(entry);
225	      if (result.error === null) retried++;
226	    } catch {
227	      // Still failed — keep as failed for next retry cycle
228	      await entry.save();
229	    }
230	  }
231	
232	  return retried;
233	}
