16	  if (!text) return null;
17	  const iv = crypto.randomBytes(IV_LENGTH);
18	  const cipher = crypto.createCipheriv(ALGORITHM, getEncryptionKey(), iv);
19	  let encrypted = cipher.update(text, 'utf8', 'hex');
20	  encrypted += cipher.final('hex');
21	  return iv.toString('hex') + ':' + encrypted;
22	}
