24	function decrypt(encryptedText) {
25	  if (!encryptedText) return null;
26	  const parts = encryptedText.split(':');
27	  const iv = Buffer.from(parts[0], 'hex');
28	  const encrypted = parts[1];
29	  const decipher = crypto.createDecipheriv(ALGORITHM, getEncryptionKey(), iv);
30	  let decrypted = decipher.update(encrypted, 'hex', 'utf8');
31	  decrypted += decipher.final('utf8');
32	  return decrypted;
33	}
