7	function requireRole(...allowedRoles) {
8	  return (req, res, next) => {
9	    if (!req.user) {
10	      return next(new ForbiddenError('Authentication required'));
11	    }
12	    if (!allowedRoles.includes(req.user.role)) {
13	      return next(new ForbiddenError(`Role '${req.user.role}' does not have permission for this action`));
14	    }
15	    next();
16	  };
17	}
