3	function errorHandler(err, req, res, _next) {
4	  // Multer file size errors
5	  if (err.code === 'LIMIT_FILE_SIZE') {
6	    return res.status(422).json({
7	      code: 'FILE_TOO_LARGE',
8	      message: 'File exceeds maximum allowed size of 10 MB'
9	    });
10	  }
11	
12	  // Multer file type errors
13	  if (err.message && err.message.includes('Only JPG and PNG')) {
14	    return res.status(422).json({
15	      code: 'INVALID_FILE_TYPE',
16	      message: err.message
17	    });
18	  }
19	
20	  // Mongoose validation errors
21	  if (err.name === 'ValidationError') {
22	    const details = Object.values(err.errors).map(e => ({
23	      field: e.path,
24	      message: e.message
25	    }));
26	    return res.status(422).json({
27	      code: 'VALIDATION_ERROR',
28	      message: 'Validation failed',
29	      details
30	    });
31	  }
32	
33	  // Mongoose duplicate key errors
34	  if (err.code === 11000) {
35	    const field = Object.keys(err.keyValue || {})[0] || 'field';
36	    return res.status(409).json({
37	      code: 'DUPLICATE',
38	      message: `Duplicate value for ${field}`
39	    });
40	  }
41	
42	  // App errors
43	  if (err instanceof AppError) {
44	    const response = {
45	      code: err.code,
46	      message: err.message
47	    };
48	    if (err.details) response.details = err.details;
49	    return res.status(err.statusCode).json(response);
50	  }
51	
52	  // Unknown errors
53	  console.error('Unhandled error:', err);
54	  res.status(500).json({
55	    code: 'INTERNAL_ERROR',
56	    message: 'An unexpected error occurred'
57	  });
58	}
59	
60	module.exports = { errorHandler };
