12	  if (!ride) throw new NotFoundError('Ride request');
13	
14	  // Non-privileged users can only dispute their own rides
15	  if (!PRIVILEGED_ROLES.includes(userRole)) {
16	    if (ride.requester.toString() !== userId.toString()) {
17	      throw new ForbiddenError('You can only dispute your own ride requests');
18	    }
19	  }
20	
21	  if (!['accepted', 'in_progress', 'completed'].includes(ride.status)) {
22	    throw new ValidationError('Can only dispute rides that are accepted, in progress, or completed');
23	  }
24	
25	  // Transition ride to in_dispute
26	  await transitionRide(ride._id, 'in_dispute', userId, `Dispute initiated: ${data.reason}`);
27	
28	  const escalationHours = await getConfig('dispute_escalation_hours', 24);
29	  const escalationDeadline = new Date(Date.now() + escalationHours * 3600000);
30	
31	  const dispute = await Dispute.create({
32	    ride_request: data.ride_request,
33	    initiated_by: userId,
34	    reason: data.reason,
35	    detail_encrypted: data.detail ? encrypt(data.detail) : null,
36	    status: 'open',
37	    escalation_deadline: escalationDeadline
38	  });
39	
40	  return dispute;
41	}
