87	async function assignDispute(disputeId, dispatcherId) {
88	  const dispute = await Dispute.findOne({ _id: disputeId, deleted_at: null });
89	  if (!dispute) throw new NotFoundError('Dispute');
90	
91	  dispute.assigned_dispatcher = dispatcherId;
