97	async function resolveDispute(disputeId, dispatcherId, resolution, notes) {
98	  const dispute = await Dispute.findOne({ _id: disputeId, deleted_at: null });
99	  if (!dispute) throw new NotFoundError('Dispute');
100	
101	  dispute.resolution = resolution;
102	  dispute.resolution_notes_encrypted = notes ? encrypt(notes) : null;
103	  dispute.status = resolution === 'escalated' ? 'escalated' : 'resolved';
104	  dispute.assigned_dispatcher = dispatcherId;
105	  await dispute.save();
106	
107	  // If resolved, transition ride back from dispute
108	  if (dispute.status === 'resolved') {
109	    const ride = await RideRequest.findById(dispute.ride_request);
110	    if (ride && ride.status === 'in_dispute') {
111	      if (['resolved_in_favor_of_rider', 'partial_refund'].includes(resolution)) {
112	        await transitionRide(ride._id, 'canceled', dispatcherId, `Dispute resolved: ${resolution}`);
113	      } else {
