    { username: 'rbac2_admin', role: 'administrator' },
    { username: 'rbac2_editor', role: 'editor' },
    { username: 'rbac2_reviewer', role: 'reviewer' },
    { username: 'rbac2_dispatcher', role: 'dispatcher' },
