3	// Test route guard logic — which roles can access which routes
4	
5	const ROUTE_PERMISSIONS = {
6	  '/dashboard': null, // all authenticated
7	  '/movies': null,
8	  '/movies/import': ['administrator', 'editor'],
9	  '/content': null,
10	  '/rides': null,
11	  '/dispatch': ['administrator', 'dispatcher'],
12	  '/sensors': ['administrator', 'dispatcher'],
13	  '/ledger': ['administrator', 'dispatcher'],
14	  '/admin/users': ['administrator'],
15	  '/admin/config': ['administrator'],
16	  '/search': null,
17	};
18	
19	function canAccessRoute(route, userRole) {
20	  const allowed = ROUTE_PERMISSIONS[route];
21	  if (allowed === null || allowed === undefined) return true; // all roles
22	  return allowed.includes(userRole);
23	}
24	
25	const ALL_ROLES = ['administrator', 'editor', 'reviewer', 'dispatcher', 'regular_user'];
26	
27	describe('Route Guards', () => {
28	  test('all roles can access shared routes', () => {
29	    const sharedRoutes = ['/dashboard', '/movies', '/content', '/rides', '/search'];
30	    for (const route of sharedRoutes) {
31	      for (const role of ALL_ROLES) {
32	        expect(canAccessRoute(route, role)).toBe(true);
33	      }
34	    }
35	  });
36	
37	  test('only admin can access admin routes', () => {
38	    for (const role of ALL_ROLES) {
39	      expect(canAccessRoute('/admin/users', role)).toBe(role === 'administrator');
40	      expect(canAccessRoute('/admin/config', role)).toBe(role === 'administrator');
41	    }
42	  });
43	
44	  test('only admin/dispatcher can access dispatch, sensors, ledger', () => {
45	    for (const role of ALL_ROLES) {
46	      const expected = ['administrator', 'dispatcher'].includes(role);
47	      expect(canAccessRoute('/dispatch', role)).toBe(expected);
48	      expect(canAccessRoute('/sensors', role)).toBe(expected);
49	      expect(canAccessRoute('/ledger', role)).toBe(expected);
50	    }
51	  });
52	
53	  test('only admin/editor can access movie import', () => {
54	    for (const role of ALL_ROLES) {
55	      const expected = ['administrator', 'editor'].includes(role);
56	      expect(canAccessRoute('/movies/import', role)).toBe(expected);
57	    }
58	  });
59	
60	  test('regular_user cannot access any restricted route', () => {
61	    const restricted = ['/movies/import', '/dispatch', '/sensors', '/ledger', '/admin/users', '/admin/config'];
62	    for (const route of restricted) {
63	      expect(canAccessRoute(route, 'regular_user')).toBe(false);
