1	const ContentItem = require('../models/ContentItem');
2	const ContentReview = require('../models/ContentReview');
3	const { validateContentTransition } = require('../utils/state-machine');
4	const { scanForSensitiveWords } = require('../utils/sensitive-words');
5	const { NotFoundError, ValidationError, ForbiddenError } = require('../utils/errors');
6	
7	function validateTypeFields(data) {
8	  const errors = [];
9	  if (data.content_type === 'gallery') {
10	    if (data.gallery_items && !Array.isArray(data.gallery_items)) {
11	      errors.push('gallery_items must be an array');
12	    }
13	  }
14	  if (data.content_type === 'video') {
15	    if (!data.video_url && !data.body) {
16	      errors.push('Video content requires a video_url or body');
17	    }
18	  }
19	  if (data.content_type === 'event') {
20	    if (!data.event_date) {
21	      errors.push('Event content requires an event_date');
22	    }
23	    if (data.event_date && data.event_end_date && new Date(data.event_end_date) <= new Date(data.event_date)) {
24	      errors.push('event_end_date must be after event_date');
25	    }
26	  }
27	  if (errors.length > 0) {
28	    throw new ValidationError('Type-specific validation failed: ' + errors.join('; '));
29	  }
30	}
31	
32	function extractTypeFields(data) {
33	  const fields = {};
34	  if (data.content_type === 'gallery') {
35	    fields.gallery_items = data.gallery_items || [];
36	  }
37	  if (data.content_type === 'video') {
38	    fields.video_url = data.video_url || null;
39	    fields.video_duration_seconds = data.video_duration_seconds || null;
40	    fields.video_format = data.video_format || null;
41	  }
42	  if (data.content_type === 'event') {
43	    fields.event_date = data.event_date || null;
44	    fields.event_end_date = data.event_end_date || null;
45	    fields.event_location = data.event_location || null;
46	    fields.event_capacity = data.event_capacity || null;
47	  }
48	  return fields;
49	}
50	
51	async function createContent(data, userId) {
52	  validateTypeFields(data);
53	  const typeFields = extractTypeFields(data);
54	
55	  const item = await ContentItem.create({
56	    content_type: data.content_type,
57	    title: data.title,
58	    body: data.body || '',
59	    ...typeFields,
60	    author: userId,
61	    status: 'draft',
62	    scheduled_publish_date: data.scheduled_publish_date || null,
63	    revisions: [{
64	      snapshot: { title: data.title, body: data.body || '', content_type: data.content_type, ...typeFields },
65	      timestamp: new Date(),
66	      changed_by: userId,
67	      change_type: 'create'
68	    }]
69	  });
70	  return item;
71	}
72	
73	async function getContentItems(filters = {}, page = 1, limit = 20, userRole = 'regular_user') {
74	  const query = { deleted_at: null };
75	
76	  // Only editorial roles (admin, editor, reviewer) can see non-published content
77	  const editorialRoles = ['administrator', 'editor', 'reviewer'];
78	  if (!editorialRoles.includes(userRole)) {
79	    query.status = 'published';
80	  } else if (filters.status) {
81	    query.status = filters.status;
82	  }
83	
84	  if (filters.content_type) query.content_type = filters.content_type;
85	  if (filters.author) query.author = filters.author;
86	  if (filters.search) {
87	    query.$text = { $search: filters.search };
88	  }
89	
90	  const total = await ContentItem.countDocuments(query);
91	  const items = await ContentItem.find(query)
92	    .select('-revisions')
93	    .populate('author', 'username display_name')
94	    .sort({ created_at: -1 })
95	    .skip((page - 1) * limit)
96	    .limit(limit);
97	
98	  return { items, total, page, pages: Math.ceil(total / limit) };
99	}
100	
101	async function getContentById(id) {
102	  const item = await ContentItem.findOne({ _id: id, deleted_at: null })
103	    .populate('author', 'username display_name');
104	  if (!item) throw new NotFoundError('Content item');
105	  return item;
106	}
107	
108	async function updateContent(id, updates, userId) {
109	  const item = await ContentItem.findOne({ _id: id, deleted_at: null });
110	  if (!item) throw new NotFoundError('Content item');
111	
112	  if (item.status !== 'draft') {
113	    throw new ValidationError('Can only edit content in draft status');
114	  }
115	
116	  if (updates.title !== undefined) item.title = updates.title;
117	  if (updates.body !== undefined) item.body = updates.body;
118	  if (updates.content_type !== undefined) item.content_type = updates.content_type;
119	  if (updates.scheduled_publish_date !== undefined) item.scheduled_publish_date = updates.scheduled_publish_date;
120	
121	  // Type-specific fields
122	  validateTypeFields({ ...item.toObject(), ...updates });
123	  const typeFields = extractTypeFields(updates.content_type ? updates : { ...item.toObject(), ...updates });
124	  for (const [k, v] of Object.entries(typeFields)) {
125	    if (updates[k] !== undefined) item[k] = updates[k];
126	    else if (v !== undefined && item[k] === undefined) item[k] = v;
127	  }
128	
129	  item.revisions.push({
130	    snapshot: { title: item.title, body: item.body, content_type: item.content_type, ...extractTypeFields(item) },
131	    timestamp: new Date(),
132	    changed_by: userId,
133	    change_type: 'edit'
134	  });
135	
136	  await item.save();
137	  return item;
138	}
139	
140	async function submitForReview(id, userId, acknowledgedSensitiveWords = false) {
141	  const item = await ContentItem.findOne({ _id: id, deleted_at: null });
142	  if (!item) throw new NotFoundError('Content item');
143	
144	  if (!validateContentTransition(item.status, 'in_review_1')) {
145	    throw new ValidationError(`Cannot submit for review from status '${item.status}'`);
146	  }
147	
148	  // Scan for sensitive words
149	  const flagged = await scanForSensitiveWords(item.title + ' ' + item.body);
150	  item.flagged_words = flagged;
151	
152	  if (flagged.length > 0 && !acknowledgedSensitiveWords) {
153	    return {
154	      item,
155	      warning: true,
156	      flagged_words: flagged,
157	      message: 'Content contains sensitive words. Set acknowledgedSensitiveWords to true to submit anyway.'
158	    };
159	  }
160	
161	  item.sensitive_words_acknowledged = flagged.length > 0 && acknowledgedSensitiveWords;
162	  item.status = 'in_review_1';
163	
164	  item.revisions.push({
165	    snapshot: { title: item.title, body: item.body, status: 'in_review_1' },
166	    timestamp: new Date(),
167	    changed_by: userId,
168	    change_type: 'submit_review'
169	  });
170	
171	  await item.save();
172	  return { item, warning: false };
173	}
174	
175	async function reviewContent(contentId, reviewerId, step, decision, rejectionReason) {
176	  const item = await ContentItem.findOne({ _id: contentId, deleted_at: null });
177	  if (!item) throw new NotFoundError('Content item');
178	
179	  const expectedStatus = step === 1 ? 'in_review_1' : 'in_review_2';
180	  if (item.status !== expectedStatus) {
181	    throw new ValidationError(`Content is not in ${expectedStatus} status`);
182	  }
183	
184	  // Enforce different reviewers for step 1 and step 2
185	  if (step === 2) {
186	    const step1Review = await ContentReview.findOne({ content_item: contentId, step: 1, decision: 'approved' });
187	    if (step1Review && step1Review.reviewer.toString() === reviewerId.toString()) {
188	      throw new ForbiddenError('Step 2 reviewer must be different from step 1 reviewer');
189	    }
190	  }
191	
192	  if (decision === 'rejected' && !rejectionReason) {
193	    throw new ValidationError('Rejection reason is required');
194	  }
195	
196	  // Create review record
197	  await ContentReview.create({
198	    content_item: contentId,
199	    reviewer: reviewerId,
200	    step,
201	    decision,
202	    rejection_reason: decision === 'rejected' ? rejectionReason : null
203	  });
204	
205	  if (decision === 'approved') {
206	    if (step === 1) {
207	      item.status = 'in_review_2';
208	    } else {
209	      // Step 2 approved — publish or schedule
210	      if (item.scheduled_publish_date && new Date(item.scheduled_publish_date) > new Date()) {
211	        item.status = 'scheduled';
212	      } else {
213	        item.status = 'published';
214	      }
215	    }
216	  } else {
217	    // Rejected — back to draft
218	    item.status = 'draft';
219	  }
220	
221	  item.revisions.push({
222	    snapshot: { status: item.status, review_step: step, decision },
223	    timestamp: new Date(),
224	    changed_by: reviewerId,
225	    change_type: decision === 'approved' ? 'publish' : 'revision'
226	  });
227	
228	  await item.save();
229	  return item;
230	}
231	
232	async function publishScheduledContent() {
233	  const now = new Date();
234	  const items = await ContentItem.find({
235	    status: 'scheduled',
236	    scheduled_publish_date: { $lte: now },
237	    deleted_at: null
238	  });
239	
240	  for (const item of items) {
241	    item.status = 'published';
242	    item.revisions.push({
243	      snapshot: { status: 'published' },
244	      timestamp: now,
245	      changed_by: null,
246	      change_type: 'publish'
247	    });
248	    await item.save();
249	  }
250	
251	  return items.length;
252	}
253	
254	async function unpublishContent(id, userId) {
255	  const item = await ContentItem.findOne({ _id: id, deleted_at: null });
256	  if (!item) throw new NotFoundError('Content item');
257	
258	  if (!['published', 'scheduled'].includes(item.status)) {
259	    throw new ValidationError('Can only unpublish published or scheduled content');
260	  }
261	
262	  item.status = 'unpublished';
263	  item.revisions.push({
264	    snapshot: { status: 'unpublished' },
265	    timestamp: new Date(),
266	    changed_by: userId,
267	    change_type: 'unpublish'
268	  });
269	  await item.save();
270	  return item;
271	}
272	
273	async function deleteContent(id) {
274	  const item = await ContentItem.findOne({ _id: id, deleted_at: null });
275	  if (!item) throw new NotFoundError('Content item');
276	  item.deleted_at = new Date();
277	  await item.save();
278	}
279	
280	async function getReviewHistory(contentId) {
281	  return ContentReview.find({ content_item: contentId })
282	    .populate('reviewer', 'username display_name')
283	    .sort({ created_at: 1 });
284	}
285	
