6	async function createRideRequest(data, userId) {
7	  const start = new Date(data.time_window_start);
8	  const end = new Date(data.time_window_end);
9	
10	  // Validate time window span <= 4 hours
11	  const spanHours = (end - start) / (1000 * 60 * 60);
12	  if (spanHours > 4) {
13	    throw new ValidationError('Time window cannot exceed 4 hours');
14	  }
15	  if (spanHours <= 0) {
16	    throw new ValidationError('End time must be after start time');
17	  }
18	
19	  // Validate start is in the future
20	  const minAdvance = await getConfig('min_ride_advance_minutes', 5);
21	  const minStart = new Date(Date.now() + minAdvance * 60000);
22	  if (start < minStart) {
23	    throw new ValidationError(`Time window must start at least ${minAdvance} minutes from now`);
24	  }
25	
26	  const autoCancelMinutes = await getConfig('auto_cancel_minutes', 30);
27	  const autoCancelAt = new Date(Date.now() + autoCancelMinutes * 60000);
28	
29	  const ride = await RideRequest.create({
30	    requester: userId,
31	    pickup_text: data.pickup_text,
32	    dropoff_text: data.dropoff_text,
33	    rider_count: data.rider_count,
34	    time_window_start: start,
35	    time_window_end: end,
36	    vehicle_type: data.vehicle_type || 'sedan',
37	    is_carpool: !!data.is_carpool,
38	    status: 'pending_match',
39	    auto_cancel_at: autoCancelAt,
40	    state_transitions: [{
41	      from: 'created',
42	      to: 'pending_match',
43	      timestamp: new Date(),
44	      actor: userId,
45	      reason: data.is_carpool ? 'Carpool request submitted' : 'Ride request submitted'
46	    }]
47	  });
48	
49	  return ride;
50	}
