4	// Use sessionStorage instead of localStorage for token storage.
5	// sessionStorage is scoped to the browser tab and cleared on close,
6	// reducing exposure window for XSS-stolen tokens compared to localStorage.
7	// A full httpOnly-cookie migration would eliminate client-side token access entirely
8	// but requires backend cookie-setting endpoints and CSRF protection — deferred.
9	const storage = sessionStorage;
10	
11	const STORAGE_KEYS = {
12	  token: 'cineride_token',
13	  user: 'cineride_user',
14	};
15	
16	// Migrate any leftover localStorage tokens to sessionStorage on first load
17	// (one-time cleanup from previous architecture)
18	function migrateFromLocalStorage() {
19	  const oldToken = localStorage.getItem(STORAGE_KEYS.token);
20	  if (oldToken) {
21	    storage.setItem(STORAGE_KEYS.token, oldToken);
22	    storage.setItem(STORAGE_KEYS.user, localStorage.getItem(STORAGE_KEYS.user) || 'null');
23	    localStorage.removeItem(STORAGE_KEYS.token);
24	    localStorage.removeItem(STORAGE_KEYS.user);
25	  }
26	}
27	migrateFromLocalStorage();
28	
29	function readUser() {
30	  try {
31	    return JSON.parse(storage.getItem(STORAGE_KEYS.user) || 'null');
32	  } catch {
33	    return null;
34	  }
35	}
36	
37	const useAuthStore = create((set, get) => ({
38	  user: readUser(),
39	  token: storage.getItem(STORAGE_KEYS.token) || null,
40	  loading: false,
41	  error: null,
42	
43	  mustChangePassword: false,
44	
45	  login: async (username, password, portal = null) => {
46	    set({ loading: true, error: null });
47	    try {
48	      const res = await api.post('/auth/login', { username, password, portal });
49	      const { token, user, must_change_password } = res;
50	      storage.setItem(STORAGE_KEYS.token, token);
51	      storage.setItem(STORAGE_KEYS.user, JSON.stringify(user));
52	      set({ user, token, loading: false, mustChangePassword: !!must_change_password });
53	      return true;
54	    } catch (err) {
55	      set({ error: err.message || 'Login failed', loading: false });
56	      return false;
57	    }
58	  },
59	
60	  logout: async () => {
61	    try {
62	      await api.post('/auth/logout');
63	    } catch {}
