65	    storage.removeItem(STORAGE_KEYS.user);
66	    set({ user: null, token: null });
67	  },
68	
69	  clearSession: () => {
70	    storage.removeItem(STORAGE_KEYS.token);
71	    storage.removeItem(STORAGE_KEYS.user);
72	    set({ user: null, token: null });
73	  },
74	
75	  isAuthenticated: () => !!get().token && !!get().user,
