    expect(SensorReading.schema.path('outlier_flags.range')).toBeDefined();
    expect(SensorReading.schema.path('outlier_flags.spike')).toBeDefined();
    expect(SensorReading.schema.path('outlier_flags.drift')).toBeDefined();
