{"file_path": "/Users/aimanmengesha/Desktop/eagle point/Slopering/newer/w2t10/repo/unit_tests/openapi-parity.test.js", "content": "const fs = require('fs');
const path = require('path');

const openapi = JSON.parse(fs.readFileSync(
  path.join(__dirname, '..', 'api', 'src', 'docs', 'openapi.json'), 'utf-8'
));

// Extract routes from the live Express app's router stack at runtime
// instead of parsing source files with regex.
const app = require('../api/src/app');

function extractExpressRoutes(expressApp) {
  const routes = [];

  function walkStack(stack, prefix) {
    for (const layer of stack) {
      if (layer.route) {
        // This is a route layer
        const routePath = prefix + layer.route.path;
        for (const method of Object.keys(layer.route.methods)) {
          if (layer.route.methods[method]) {
            routes.push({ method: method.toUpperCase(), path: routePath });
          }
        }
      } else if (layer.name === 'router' && layer.handle && layer.handle.stack) {
        // This is a nested router — extract its mount prefix from the regexp
        let mountPath = '';
        if (layer.regexp) {
          const match = layer.regexp.source
            .replace('\\/?', '')
            .replace('(?=\\/|$)', '')
            .replace(/\\\//g, '/')
            .replace(/^\^/, '');
          if (match && match !== '' && match !== '/') {
            mountPath = match;
          }
        }
        walkStack(layer.handle.stack, prefix + mountPath);
      }
    }
  }

  if (expressApp._router && expressApp._router.stack) {
    walkStack(expressApp._router.stack, '');
  }

  // Filter to /api/ routes and normalize path — strip /api prefix to match OpenAPI
  return routes
    .filter(r => r.path.startsWith('/api/'))
    .map(r => ({ ...r, path: r.path.replace(/^\/api/, '') }))
    // Exclude the docs and health routes that are defined inline (not in route files)
    // Health is expected in OpenAPI; docs.json is not an API endpoint
    .filter(r => !r.path.startsWith('/docs'));
}

const allImplementedRoutes = extractExpressRoutes(app);

function normalizeParam(p) {
  return p.replace(/:[a-zA-Z]+/g, ':param').replace(/\{[^}]+\}/g, ':param');
}

const openapiRouteMethodPairs = new Set();
for (const [oaPath, methods] of Object.entries(openapi.paths)) {
  for (const method of Object.keys(methods)) {
    const httpMethod = method.toUpperCase();
    if (['GET', 'POST', 'PUT', 'DELETE', 'PATCH'].includes(httpMethod)) {
      openapiRouteMethodPairs.add(`${httpMethod} ${normalizeParam(oaPath)}`);
    }
  }
}

describe('OpenAPI Parity — Strict 100% Coverage', () => {
  test('OpenAPI spec exists and has paths', () => {
    expect(Object.keys(openapi.paths).length).toBeGreaterThan(10);
  });

  test('runtime router has a reasonable number of routes', () => {
    // Sanity check that extraction worked
    expect(allImplementedRoutes.length).toBeGreaterThan(30);
  });

  test('every implemented route+method is documented in OpenAPI', () => {
    const undocumented = [];
    for (const r of allImplementedRoutes) {
      const normalized = normalizeParam(r.path);
      const key = `${r.method} ${normalized}`;
      if (!openapiRouteMethodPairs.has(key)) {
        undocumented.push(`${r.method} ${r.path}`);
      }
    }
    if (undocumented.length > 0) {
      fail(
        `OpenAPI spec is missing ${undocumented.length} route(s):\n` +
        undocumented.map(u => `  - ${u}`).join('\n')
      );
    }
  });

  test('100% route+method parity (no undocumented routes allowed)', () => {
    let documented = 0;
    for (const r of allImplementedRoutes) {
      const normalized = normalizeParam(r.path);
      const key = `${r.method} ${normalized}`;
      if (openapiRouteMethodPairs.has(key)) documented++;
    }
    const coverage = allImplementedRoutes.length > 0
      ? documented / allImplementedRoutes.length
      : 0;
    expect(coverage).toBe(1);
  });

  test('sensor ingest documents device auth headers', () => {
    const ingest = openapi.paths['/sensors/ingest'];
    expect(ingest).toBeTruthy();
    const params = ingest.post.parameters || [];
    const headerNames = params.map(p => p.name);
    expect(headerNames).toContain('X-Device-Id');
    expect(headerNames).toContain('X-Device-Secret');
  });

  test('all major route groups are represented in OpenAPI', () => {
    const openapiPaths = Object.keys(openapi.paths);
    const openapiGroups = new Set(openapiPaths.map(p => '/' + p.split('/')[1]));
    const requiredGroups = ['/auth', '/users', '/movies', '/content', '/rides',
      '/dispatch', '/search', '/sensors', '/ledger', '/config', '/health'];
    for (const g of requiredGroups) {
      expect(openapiGroups.has(g)).toBe(true);
    }
  });
});
"}

