var app = require('./api/src/app');
var fs = require('fs');
var path = require('path');
var openapi = JSON.parse(fs.readFileSync(path.join(__dirname, 'api/src/docs/openapi.json'), 'utf-8'));

function extractMountPath(layer) {
  if (!layer.regexp) return '';
  var src = layer.regexp.source;
  var match = src.match(/^\^\\\\\/api(\\\\\/[a-z0-9-]+(?:\\\\\/[a-z0-9-]+)*)\\\\\/\?/);
  if (match) return match[1].replace(/\\\\\//g, '/');
  return null;
}

var routes = [];
// Inline
app._router.stack.forEach(function(layer) {
  if (layer.route && layer.route.path && layer.route.path.startsWith('/api/')) {
    var rp = layer.route.path.replace(/^\/api/, '');
    Object.keys(layer.route.methods).forEach(function(m) {
      if (layer.route.methods[m]) routes.push(m.toUpperCase() + ' ' + rp);
    });
  }
  if (layer.name === 'router' && layer.handle && layer.handle.stack) {
    var mp = extractMountPath(layer);
    if (mp === null) return;
    layer.handle.stack.forEach(function(rl) {
      if (rl.route) {
        Object.keys(rl.route.methods).forEach(function(m) {
          if (rl.route.methods[m]) routes.push(m.toUpperCase() + ' ' + mp + rl.route.path);
        });
      }
    });
  }
});

routes = routes.filter(function(r) { return !r.includes('/docs'); });

// Check against OpenAPI
function norm(p) { return p.replace(/:[a-zA-Z]+/g, ':param').replace(/\{[^}]+\}/g, ':param'); }
var oaPairs = new Set();
Object.keys(openapi.paths).forEach(function(oap) {
  Object.keys(openapi.paths[oap]).forEach(function(m) {
    var hm = m.toUpperCase();
    if (['GET','POST','PUT','DELETE'].includes(hm)) oaPairs.add(hm + ' ' + norm(oap));
  });
});

var undoc = routes.filter(function(r) {
  var parts = r.split(' ');
  return !oaPairs.has(parts[0] + ' ' + norm(parts[1]));
});
console.log('Undocumented: ' + undoc.length);
undoc.forEach(function(u) { console.log('  ' + u); });
console.log('Total routes: ' + routes.length);
