8	function sanitizeForLog(err) {
9	  const safe = {
10	    message: err.message || 'Unknown error',
11	    code: err.code || 'INTERNAL_ERROR',
12	    correlation_id: crypto.randomUUID()
13	  };
14	
15	  // Only include stack traces in non-production environments
16	  if (process.env.NODE_ENV !== 'production') {
17	    safe.stack = err.stack;
18	  }
19	
20	  return safe;
21	}
