23	function errorHandler(err, req, res, _next) {
24	  // Multer file size errors
25	  if (err.code === 'LIMIT_FILE_SIZE') {
26	    return res.status(422).json({
27	      code: 'FILE_TOO_LARGE',
28	      message: 'File exceeds maximum allowed size of 10 MB'
29	    });
30	  }
31	
32	  // Multer file type errors
33	  if (err.message && err.message.includes('Only JPG and PNG')) {
34	    return res.status(422).json({
35	      code: 'INVALID_FILE_TYPE',
36	      message: err.message
37	    });
38	  }
39	
40	  // Mongoose validation errors
41	  if (err.name === 'ValidationError') {
42	    const details = Object.values(err.errors).map(e => ({
43	      field: e.path,
44	      message: e.message
45	    }));
46	    return res.status(422).json({
47	      code: 'VALIDATION_ERROR',
48	      message: 'Validation failed',
49	      details
50	    });
51	  }
52	
53	  // Mongoose duplicate key errors
54	  if (err.code === 11000) {
55	    const field = Object.keys(err.keyValue || {})[0] || 'field';
56	    return res.status(409).json({
57	      code: 'DUPLICATE',
58	      message: `Duplicate value for ${field}`
59	    });
60	  }
61	
62	  // App errors
63	  if (err instanceof AppError) {
64	    const response = {
65	      code: err.code,
66	      message: err.message
67	    };
68	    if (err.details) response.details = err.details;
69	    return res.status(err.statusCode).json(response);
70	  }
71	
72	  // Unknown errors — safe logging only
73	  const safeLog = sanitizeForLog(err);
74	  console.error('Unhandled error:', safeLog);
75	  res.status(500).json({
76	    code: 'INTERNAL_ERROR',
77	    message: 'An unexpected error occurred',
78	    correlation_id: safeLog.correlation_id
79	  });
80	}
