13	async function extensionAuth(req, res, next) {
14	  const apiKey = req.headers['x-api-key'];
15	  if (!apiKey) {
16	    return res.status(401).json({ code: 'UNAUTHORIZED', message: 'API key required' });
17	  }
18	
19	  // O(1) indexed lookup using key prefix
20	  const prefix = apiKey.substring(0, API_KEY_PREFIX_LENGTH);
21	  const candidates = await ExtensionClient.find({
22	    api_key_prefix: prefix,
23	    status: 'active'
24	  });
25	
26	  let matchedClient = null;
27	  for (const client of candidates) {
28	    if (await bcrypt.compare(apiKey, client.api_key_hash)) {
29	      matchedClient = client;
30	      break;
31	    }
32	  }
33	
34	  if (!matchedClient) {
35	    return res.status(401).json({ code: 'UNAUTHORIZED', message: 'Invalid API key' });
36	  }
37	
38	  // DB-backed rate limiting (persistent across restarts)
39	  const now = new Date();
40	  const windowStart = new Date(now.getTime() - 60000);
41	
42	  // Clean old entries and count recent hits atomically
43	  await ExtensionClient.updateOne(
44	    { _id: matchedClient._id },
45	    { $pull: { rate_limit_hits: { timestamp: { $lt: windowStart } } } }
46	  );
47	
48	  const freshClient = await ExtensionClient.findById(matchedClient._id);
49	  const recentHits = (freshClient.rate_limit_hits || []).filter(
50	    h => h.timestamp >= windowStart
51	  );
52	
53	  if (recentHits.length >= matchedClient.rate_limit) {
54	    return res.status(429).json({ code: 'RATE_LIMITED', message: 'Rate limit exceeded' });
55	  }
56	
57	  // Record this hit
58	  await ExtensionClient.updateOne(
59	    { _id: matchedClient._id },
60	    {
61	      $push: { rate_limit_hits: { timestamp: now } },
62	      $set: { last_used_at: now }
63	    }
64	  );
65	
66	  req.extensionClient = matchedClient;
67	  next();
68	}
