3	const { encrypt, decrypt } = require('../utils/crypto');
4	const { getConfig } = require('./config.service');
5	const { transitionRide } = require('./ride.service');
6	const { NotFoundError, ValidationError, ForbiddenError } = require('../utils/errors');
7	
8	const PRIVILEGED_ROLES = ['administrator', 'dispatcher'];
9	
10	async function createDispute(data, userId, userRole) {
11	  const ride = await RideRequest.findOne({ _id: data.ride_request, deleted_at: null });
12	  if (!ride) throw new NotFoundError('Ride request');
13	
14	  // Non-privileged users can only dispute their own rides
15	  if (!PRIVILEGED_ROLES.includes(userRole)) {
16	    if (ride.requester.toString() !== userId.toString()) {
17	      throw new ForbiddenError('You can only dispute your own ride requests');
18	    }
19	  }
20	
21	  if (!['accepted', 'in_progress', 'completed'].includes(ride.status)) {
22	    throw new ValidationError('Can only dispute rides that are accepted, in progress, or completed');
23	  }
24	
25	  // Transition ride to in_dispute
26	  await transitionRide(ride._id, 'in_dispute', userId, `Dispute initiated: ${data.reason}`);
27	
28	  const escalationHours = await getConfig('dispute_escalation_hours', 24);
29	  const escalationDeadline = new Date(Date.now() + escalationHours * 3600000);
30	
31	  const dispute = await Dispute.create({
32	    ride_request: data.ride_request,
33	    initiated_by: userId,
34	    reason: data.reason,
35	    detail_encrypted: data.detail ? encrypt(data.detail) : null,
36	    status: 'open',
37	    escalation_deadline: escalationDeadline
38	  });
39	
40	  return dispute;
41	}
42	
43	async function getDisputes(filters = {}, page = 1, limit = 20) {
44	  const query = { deleted_at: null };
45	  if (filters.status) query.status = filters.status;
46	  if (filters.assigned_dispatcher) query.assigned_dispatcher = filters.assigned_dispatcher;
47	
48	  const total = await Dispute.countDocuments(query);
49	  const disputes = await Dispute.find(query)
50	    .populate('ride_request', 'pickup_text dropoff_text status')
51	    .populate('initiated_by', 'username display_name')
52	    .populate('assigned_dispatcher', 'username display_name')
53	    .sort({ created_at: -1 })
54	    .skip((page - 1) * limit)
55	    .limit(limit);
56	
57	  // Decrypt detail for display in list
58	  const decryptedDisputes = disputes.map(d => {
59	    const obj = d.toObject();
60	    if (obj.detail_encrypted) {
61	      obj.detail = decrypt(obj.detail_encrypted);
62	    }
63	    return obj;
64	  });
65	
66	  return { disputes: decryptedDisputes, total, page, pages: Math.ceil(total / limit) };
67	}
68	
69	async function getDisputeById(id) {
70	  const dispute = await Dispute.findOne({ _id: id, deleted_at: null })
71	    .populate('ride_request')
72	    .populate('initiated_by', 'username display_name')
73	    .populate('assigned_dispatcher', 'username display_name');
74	  if (!dispute) throw new NotFoundError('Dispute');
75	
76	  // Decrypt encrypted fields for display
77	  if (dispute.detail_encrypted) {
78	    dispute._doc.detail = decrypt(dispute.detail_encrypted);
79	  }
80	  if (dispute.resolution_notes_encrypted) {
81	    dispute._doc.resolution_notes = decrypt(dispute.resolution_notes_encrypted);
82	  }
83	
84	  return dispute;
85	}
86	
87	async function assignDispute(disputeId, dispatcherId, userRole) {
88	  const dispute = await Dispute.findOne({ _id: disputeId, deleted_at: null });
89	  if (!dispute) throw new NotFoundError('Dispute');
90	
91	  // Only admin can reassign if already assigned to someone else
92	  if (dispute.assigned_dispatcher &&
93	      dispute.assigned_dispatcher.toString() !== dispatcherId.toString() &&
94	      userRole !== 'administrator') {
95	    throw new ForbiddenError('Only the assigned dispatcher or an admin can modify this dispute');
96	  }
97	
98	  dispute.assigned_dispatcher = dispatcherId;
99	  dispute.status = 'investigating';
100	  await dispute.save();
101	  return dispute;
102	}
103	
104	function enforceDisputeAccess(dispute, userId, userRole) {
105	  if (userRole === 'administrator') return; // admin override
106	  if (!dispute.assigned_dispatcher) {
107	    throw new ForbiddenError('Dispute must be assigned before it can be resolved');
108	  }
109	  if (dispute.assigned_dispatcher.toString() !== userId.toString()) {
110	    throw new ForbiddenError('Only the assigned dispatcher or an admin can modify this dispute');
111	  }
112	}
113	
114	async function resolveDispute(disputeId, dispatcherId, resolution, notes, userRole) {
115	  const dispute = await Dispute.findOne({ _id: disputeId, deleted_at: null });
116	  if (!dispute) throw new NotFoundError('Dispute');
117	
118	  enforceDisputeAccess(dispute, dispatcherId, userRole);
119	
120	  dispute.resolution = resolution;
121	  dispute.resolution_notes_encrypted = notes ? encrypt(notes) : null;
122	  dispute.status = resolution === 'escalated' ? 'escalated' : 'resolved';
123	  dispute.assigned_dispatcher = dispatcherId;
124	  await dispute.save();
125	
126	  // If resolved, transition ride back from dispute
127	  if (dispute.status === 'resolved') {
128	    const ride = await RideRequest.findById(dispute.ride_request);
129	    if (ride && ride.status === 'in_dispute') {
130	      if (['resolved_in_favor_of_rider', 'partial_refund'].includes(resolution)) {
131	        await transitionRide(ride._id, 'canceled', dispatcherId, `Dispute resolved: ${resolution}`);
132	      } else {
133	        await transitionRide(ride._id, 'completed', dispatcherId, `Dispute resolved: ${resolution}`);
134	      }
135	    }
136	  }
137	
138	  return dispute;
139	}
140	
141	module.exports = {
142	  createDispute,
143	  getDisputes,
144	  getDisputeById,
145	  assignDispute,
146	  resolveDispute
147	};
