5	import App from '../App';
6	
7	const ALL_ROLES = ['administrator', 'editor', 'reviewer', 'dispatcher', 'regular_user'];
8	
9	function setAuth(role) {
10	  const store = useAuthStore.getState();
11	  // Directly set store state to simulate authenticated user
12	  useAuthStore.setState({
