17	}
18	
19	function clearAuth() {
20	  useAuthStore.setState({ user: null, token: null, mustChangePassword: false });
21	}
22	
23	function renderRoute(path) {
24	  return render(
25	    <MemoryRouter initialEntries={[path]}>
