29	}
30	
31	beforeEach(() => {
32	  clearAuth();
33	});
34	
35	describe('Route Guards — Unauthenticated', () => {
36	  test('unauthenticated user visiting /movies is redirected to /login', () => {
37	    renderRoute('/movies');
38	    // Should see the login page, not movies
39	    expect(screen.queryByText(/Sign in/i) || screen.queryByText(/Login/i) || screen.queryByText(/username/i)).toBeTruthy();
40	  });
41	
42	  test('unauthenticated user visiting /admin/users is redirected to /login', () => {
