1	const express = require('express');
2	const router = express.Router();
3	const sensorService = require('../services/sensor.service');
4	const { authMiddleware } = require('../middleware/auth.middleware');
5	const { requireRole, adminOnly } = require('../middleware/rbac.middleware');
6	const { sensorIngestValidation, mongoIdParam, paginationValidation } = require('../middleware/validation.middleware');
7	
8	// Per-device secret authentication for sensor ingest endpoints.
9	// Requires headers:
10	//   X-Device-Id: the device_id
11	//   X-Device-Secret: a per-device secret set when the device is registered
12	// The body device_id must match the header device_id (prevents cross-device spoofing).
13	async function deviceAuth(req, res, next) {
14	  const deviceId = req.headers['x-device-id'];
15	  const deviceSecret = req.headers['x-device-secret'];
16	  if (!deviceId || !deviceSecret) {
17	    return res.status(401).json({ code: 'UNAUTHORIZED', message: 'X-Device-Id and X-Device-Secret headers required' });
18	  }
19	  const SensorDevice = require('../models/SensorDevice');
20	  const bcrypt = require('bcryptjs');
21	  const device = await SensorDevice.findOne({ device_id: deviceId, status: 'active', deleted_at: null });
22	  if (!device || !device.secret_hash) {
23	    return res.status(401).json({ code: 'UNAUTHORIZED', message: 'Unknown or inactive device, or no secret configured' });
24	  }
25	  const valid = await bcrypt.compare(deviceSecret, device.secret_hash);
26	  if (!valid) {
27	    return res.status(401).json({ code: 'UNAUTHORIZED', message: 'Invalid device secret' });
28	  }
29	  req.sensorDevice = device;
30	  next();
31	}
32	
33	// Body-header identity enforcement: body device_id must match authenticated header
34	function enforceDeviceIdentity(req, res, next) {
35	  const headerDeviceId = req.headers['x-device-id'];
36	  const bodyDeviceId = req.body?.device_id;
37	  // For single ingest, enforce exact match
38	  if (bodyDeviceId && bodyDeviceId !== headerDeviceId) {
39	    return res.status(403).json({
40	      code: 'FORBIDDEN',
41	      message: `Body device_id '${bodyDeviceId}' does not match authenticated device '${headerDeviceId}'`
42	    });
43	  }
44	  // For batch, enforce all readings match
45	  if (req.body?.readings && Array.isArray(req.body.readings)) {
46	    const mismatch = req.body.readings.find(r => r.device_id && r.device_id !== headerDeviceId);
47	    if (mismatch) {
48	      return res.status(403).json({
49	        code: 'FORBIDDEN',
50	        message: `Batch contains reading for device '${mismatch.device_id}' but authenticated as '${headerDeviceId}'`
51	      });
52	    }
53	  }
54	  next();
55	}
56	
57	// POST /api/sensors/ingest — requires per-device secret + identity match
58	router.post('/ingest', deviceAuth, enforceDeviceIdentity, sensorIngestValidation, async (req, res, next) => {
59	  try {
60	    const reading = await sensorService.ingestReading(req.body);
61	    res.status(201).json({ reading });
62	  } catch (err) { next(err); }
63	});
64	
65	// POST /api/sensors/ingest/batch — requires per-device secret + identity match
66	router.post('/ingest/batch', deviceAuth, enforceDeviceIdentity, async (req, res, next) => {
