7	async function ingestReading(data) {
8	  const device = await SensorDevice.findOne({ device_id: data.device_id, deleted_at: null });
9	  if (!device) throw new NotFoundError(`Sensor device '${data.device_id}'`);
10	
11	  const timestamp = new Date(data.timestamp);
12	
13	  // Deduplication check
14	  const exists = await SensorReading.findOne({ device_id: data.device_id, timestamp, is_raw: true });
15	  if (exists) {
16	    throw new ConflictError(`Reading already exists for device ${data.device_id} at ${timestamp.toISOString()}`);
17	  }
18	
19	  // Time synchronization check
20	  const driftThreshold = await getConfig('time_drift_threshold_seconds', 300);
21	  const serverNow = new Date();
22	  const timeDriftSeconds = Math.abs((timestamp - serverNow) / 1000);
23	  const hasTimeDrift = timeDriftSeconds > driftThreshold;
24	
25	  const outlierFlags = { range: false, spike: false, drift: false, time_drift: hasTimeDrift };
26	
27	  if (device.range_min !== null && data.value < device.range_min) outlierFlags.range = true;
28	  if (device.range_max !== null && data.value > device.range_max) outlierFlags.range = true;
29	
30	  if (device.spike_threshold !== null) {
31	    const prev = await SensorReading.findOne({ device_id: data.device_id, is_raw: true })
32	      .sort({ timestamp: -1 }).limit(1);
33	    if (prev && Math.abs(data.value - prev.value) > device.spike_threshold) {
34	      outlierFlags.spike = true;
35	    }
36	  }
37	
38	  if (device.drift_threshold !== null) {
39	    const window = device.drift_window || 10;
40	    const recentReadings = await SensorReading.find({ device_id: data.device_id, is_raw: true })
41	      .sort({ timestamp: -1 }).limit(window);
42	    if (recentReadings.length >= window) {
43	      const oldest = recentReadings[recentReadings.length - 1].value;
44	      if (Math.abs(data.value - oldest) > device.drift_threshold) {
45	        outlierFlags.drift = true;
46	      }
47	    }
48	  }
49	
50	  const hasOutlier = outlierFlags.range || outlierFlags.spike || outlierFlags.drift || outlierFlags.time_drift;
51	  const retentionDays = await getConfig('sensor_retention_days', 180);
52	  const expiresAt = new Date(Date.now() + retentionDays * 86400000);
53	
54	  // Always store the raw reading
55	  const rawReading = await SensorReading.create({
56	    device_id: data.device_id,
57	    timestamp,
58	    value: data.value,
59	    unit: data.unit || device.unit || '',
60	    is_raw: true,
61	    is_cleaned: false,
62	    outlier_flags: outlierFlags,
63	    time_drift_seconds: timeDriftSeconds,
64	    expires_at: expiresAt
65	  });
66	
67	  // If no outlier, also store a cleaned copy
68	  // If outlier detected, store cleaned version with null value (excluded from cleaned queries)
69	  if (!hasOutlier) {
70	    await SensorReading.create({
71	      device_id: data.device_id,
72	      timestamp,
73	      value: data.value,
74	      unit: data.unit || device.unit || '',
75	      is_raw: false,
76	      is_cleaned: true,
77	      outlier_flags: { range: false, spike: false, drift: false },
78	      time_drift_seconds: timeDriftSeconds,
79	      expires_at: expiresAt
80	    });
81	  }
82	
83	  return rawReading;
84	}
