86	async function ingestBatch(readings, sessionId = null, deviceId = null) {
87	  const results = { ingested: 0, duplicates: 0, errors: [], session_id: null, resume_offset: 0 };
88	  const crypto = require('crypto');
89	  const SESSION_TTL_MS = 3600000;
90	
91	  let startOffset = 0;
92	  if (sessionId) {
93	    const session = await BatchSession.findOne({ session_id: sessionId });
94	    if (session) {
95	      startOffset = session.processed;
96	      results.resume_offset = startOffset;
97	    }
98	    results.session_id = sessionId;
99	  } else {
100	    results.session_id = `batch_${crypto.randomBytes(8).toString('hex')}`;
101	  }
102	
103	  const expiresAt = new Date(Date.now() + SESSION_TTL_MS);
104	
105	  for (let i = startOffset; i < readings.length; i++) {
106	    const r = readings[i];
107	    try {
108	      await ingestReading(r);
109	      results.ingested++;
110	    } catch (err) {
111	      if (err instanceof ConflictError) {
112	        results.duplicates++;
113	      } else {
114	        results.errors.push({ index: i, device_id: r.device_id, timestamp: r.timestamp, error: err.message });
115	      }
116	    }
117	
118	    if (results.session_id) {
119	      await BatchSession.findOneAndUpdate(
120	        { session_id: results.session_id },
121	        { session_id: results.session_id, device_id: deviceId || r.device_id, processed: i + 1, expires_at: expiresAt },
122	        { upsert: true }
123	      );
124	    }
125	  }
126	
127	  return results;
128	}
