130	async function getReadings(deviceId, filters = {}, page = 1, limit = 100) {
131	  const query = { device_id: deviceId };
132	  if (filters.from) query.timestamp = { ...query.timestamp, $gte: new Date(filters.from) };
133	  if (filters.to) query.timestamp = { ...query.timestamp, $lte: new Date(filters.to) };
134	  if (filters.cleaned_only) {
135	    query.is_cleaned = true;
136	    query.is_raw = false;
137	  } else if (filters.raw_only) {
138	    query.is_raw = true;
139	  }
140	  if (filters.outliers_only) {
141	    query.is_raw = true;
142	    query.$or = [
143	      { 'outlier_flags.range': true },
144	      { 'outlier_flags.spike': true },
145	      { 'outlier_flags.drift': true }
146	    ];
147	  }
148	
149	  const total = await SensorReading.countDocuments(query);
150	  const readings = await SensorReading.find(query)
151	    .sort({ timestamp: -1 })
152	    .skip((page - 1) * limit)
153	    .limit(limit);
154	
155	  return { readings, total, page, pages: Math.ceil(total / limit) };
156	}
