5	function maskPhone(phone) {
6	  if (!phone) return null;
7	
8	  // Strip non-digit characters
9	  const digits = phone.replace(/\D/g, '');
10	
11	  if (digits.length < 7) {
12	    return '***-' + digits.slice(-2);
13	  }
14	
15	  if (digits.length >= 10) {
16	    const area = digits.slice(-10, -7);
17	    const last2 = digits.slice(-2);
18	    return `(${area}) ***-**${last2}`;
19	  }
20	
21	  const last2 = digits.slice(-2);
22	  return `***-**${last2}`;
23	}
