2	
3	describe('Structured Logger', () => {
4	  test('formatEntry produces valid JSON with required fields', () => {
5	    const raw = formatEntry('info', 'test message', { foo: 'bar' });
6	    const parsed = JSON.parse(raw);
7	    expect(parsed.level).toBe('info');
8	    expect(parsed.message).toBe('test message');
9	    expect(parsed.foo).toBe('bar');
10	    expect(parsed.timestamp).toBeDefined();
11	  });
12	
13	  test('formatEntry includes ISO timestamp', () => {
14	    const raw = formatEntry('warn', 'check');
15	    const parsed = JSON.parse(raw);
16	    expect(parsed.timestamp).toMatch(/^\d{4}-\d{2}-\d{2}T/);
17	  });
18	
19	  test('redactSensitive strips password field', () => {
20	    const result = redactSensitive({ username: 'admin', password: 'secret123' });
21	    expect(result.username).toBe('admin');
22	    expect(result.password).toBe('[REDACTED]');
23	  });
24	
25	  test('redactSensitive strips token and api_key', () => {
26	    const result = redactSensitive({ token: 'jwt-value', api_key: 'key-value', status: 200 });
27	    expect(result.token).toBe('[REDACTED]');
28	    expect(result.api_key).toBe('[REDACTED]');
29	    expect(result.status).toBe(200);
30	  });
31	
32	  test('redactSensitive handles null/undefined gracefully', () => {
33	    expect(redactSensitive(null)).toBeNull();
34	    expect(redactSensitive(undefined)).toBeUndefined();
35	  });
36	
37	  test('SENSITIVE_KEYS list covers critical fields', () => {
38	    const required = ['password', 'token', 'secret', 'api_key', 'authorization'];
39	    for (const key of required) {
40	      expect(SENSITIVE_KEYS).toContain(key);
41	    }
42	  });
43	
44	  test('formatEntry redacts sensitive meta fields', () => {
45	    const raw = formatEntry('error', 'login failed', {
46	      username: 'admin',
47	      password: 'leaked',
48	      token: 'jwt-leaked'
49	    });
50	    const parsed = JSON.parse(raw);
51	    expect(parsed.username).toBe('admin');
52	    expect(parsed.password).toBe('[REDACTED]');
