1	import React, { useState, useEffect, useRef } from 'react';
2	import { useSearchParams } from 'react-router-dom';
3	import api from '../../services/api';
4	import useAuthStore from '../../store/authStore';
5	import StatusBadge from '../../components/ui/StatusBadge';
6	import { formatDate } from '../../utils/formatters';
7	
8	export default function SearchPage() {
9	  const { user } = useAuthStore();
10	  const canSearchUsers = ['administrator', 'dispatcher'].includes(user?.role);
11	  const [searchParams, setSearchParams] = useSearchParams();
12	  const [query, setQuery] = useState(searchParams.get('q') || '');
13	  const [results, setResults] = useState({ movies: [], content: [], users: [], total: 0 });
14	  const [type, setType] = useState('');
15	  const [sort, setSort] = useState('');
16	  const [loading, setLoading] = useState(false);
17	  const [error, setError] = useState(null);
18	
19	  // Use refs to avoid stale closures when filters change
20	  const typeRef = useRef(type);
21	  const sortRef = useRef(sort);
22	  typeRef.current = type;
23	  sortRef.current = sort;
24	
25	  useEffect(() => {
26	    const q = searchParams.get('q');
27	    if (q) {
28	      setQuery(q);
29	      doSearch(q, typeRef.current, sortRef.current);
30	    }
31	  }, [searchParams]);
32	
33	  async function doSearch(q, searchType, searchSort) {
34	    if (!q || !q.trim()) return;
35	    setLoading(true);
36	    setError(null);
37	    try {
38	      const params = new URLSearchParams({ q: q.trim() });
39	      if (searchType) params.set('type', searchType);
40	      if (searchSort) params.set('sort', searchSort);
41	      const res = await api.get(`/search?${params}`);
42	      setResults(res);
43	    } catch (err) {
44	      setError(err.message || 'Search failed. Please try again.');
45	      setResults({ movies: [], content: [], users: [], total: 0 });
46	    }
47	    setLoading(false);
48	  }
49	
50	  const handleSearch = (e) => {
51	    e.preventDefault();
52	    setSearchParams({ q: query });
53	    doSearch(query, type, sort);
54	  };
55	
56	  function handleTypeChange(newType) {
57	    setType(newType);
58	    if (query) doSearch(query, newType, sort);
59	  }
60	
61	  function handleSortChange(newSort) {
62	    setSort(newSort);
63	    if (query) doSearch(query, type, newSort);
64	  }
65	
66	  return (
67	    <div className="space-y-4">
68	      <h1 className="text-xl font-bold">Search</h1>
69	
70	      <form onSubmit={handleSearch} className="flex flex-col sm:flex-row gap-2">
71	        <input className="input flex-1" value={query} onChange={e => setQuery(e.target.value)}
72	          placeholder="Search movies, content, users..." autoFocus />
73	        <button type="submit" className="btn-primary w-full sm:w-auto">Search</button>
74	      </form>
75	
76	      <div className="flex flex-wrap gap-2">
77	        {['', 'movie', 'content', ...(canSearchUsers ? ['user'] : [])].map(t => (
78	          <button key={t} className={`btn-sm ${type === t ? 'btn-primary' : 'btn-outline'}`}
79	            onClick={() => handleTypeChange(t)}>
80	            {t || 'All'}{t === 'movie' ? 's' : t === 'user' ? 's' : ''}
81	          </button>
82	        ))}
83	        <select className="input w-full sm:w-36 h-8 text-xs" value={sort}
84	          onChange={e => handleSortChange(e.target.value)}>
85	          <option value="">Relevance</option>
86	          <option value="popularity">Popularity</option>
87	          <option value="newest">Newest</option>
88	          <option value="rating">Rating</option>
89	        </select>
90	      </div>
91	
92	      {loading && <div className="text-center text-muted-foreground py-8">Searching...</div>}
93	
94	      {error && (
95	        <div className="bg-red-50 dark:bg-red-950/20 border border-red-200 dark:border-red-800 rounded-lg p-4 text-sm text-red-700 dark:text-red-300">
96	          {error}
97	        </div>
98	      )}
99	
100	      {!loading && !error && results.total > 0 && (
101	        <div className="space-y-6">
102	          <p className="text-sm text-muted-foreground">{results.total} results found</p>
103	
104	          {results.movies?.length > 0 && (
105	            <div>
106	              <h2 className="font-semibold mb-2">Movies ({results.movies.length})</h2>
107	              <div className="grid grid-cols-2 md:grid-cols-4 gap-3">
108	                {results.movies.map(m => (
109	                  <div key={m._id} className="card p-3">
110	                    <h3 className="font-medium text-sm">{m.title}</h3>
111	                    <div className="flex gap-1 mt-1">
112	                      <span className={`badge-${(m.mpaa_rating || 'NR').replace('-', '')} text-[10px]`}>{m.mpaa_rating}</span>
113	                    </div>
114	                    <p className="text-xs text-muted-foreground mt-1 line-clamp-2">{m.description}</p>
115	                    <div className="text-xs text-muted-foreground mt-1">{formatDate(m.release_date)}</div>
116	                  </div>
117	                ))}
118	              </div>
119	            </div>
120	          )}
121	
122	          {results.content?.length > 0 && (
123	            <div>
124	              <h2 className="font-semibold mb-2">Content ({results.content.length})</h2>
125	              <div className="space-y-2">
126	                {results.content.map(c => (
127	                  <div key={c._id} className="card p-3 flex justify-between">
128	                    <div>
129	                      <h3 className="font-medium text-sm">{c.title}</h3>
130	                      <p className="text-xs text-muted-foreground capitalize">{c.content_type} · {c.author?.display_name}</p>
131	                    </div>
132	                    <StatusBadge status={c.status} />
133	                  </div>
134	                ))}
135	              </div>
