13	async function extensionAuth(req, res, next) {
14	  const apiKey = req.headers['x-api-key'];
15	  if (!apiKey) {
16	    return res.status(401).json({ code: 'UNAUTHORIZED', message: 'API key required' });
17	  }
18	
19	  const prefix = apiKey.substring(0, API_KEY_PREFIX_LENGTH);
20	  const candidates = await ExtensionClient.find({
21	    api_key_prefix: prefix,
22	    status: 'active'
23	  });
24	
25	  let matchedClient = null;
26	  for (const client of candidates) {
27	    if (await bcrypt.compare(apiKey, client.api_key_hash)) {
28	      matchedClient = client;
29	      break;
30	    }
31	  }
32	
33	  if (!matchedClient) {
34	    return res.status(401).json({ code: 'UNAUTHORIZED', message: 'Invalid API key' });
35	  }
36	
37	  const now = new Date();
38	  const windowStart = new Date(now.getTime() - 60000);
39	
40	  await ExtensionClient.updateOne(
41	    { _id: matchedClient._id },
42	    { $pull: { rate_limit_hits: { timestamp: { $lt: windowStart } } } }
43	  );
44	
45	  const freshClient = await ExtensionClient.findById(matchedClient._id);
46	  const recentHits = (freshClient.rate_limit_hits || []).filter(
47	    h => h.timestamp >= windowStart
48	  );
49	
50	  if (recentHits.length >= matchedClient.rate_limit) {
51	    return res.status(429).json({ code: 'RATE_LIMITED', message: 'Rate limit exceeded' });
52	  }
53	
54	  await ExtensionClient.updateOne(
55	    { _id: matchedClient._id },
56	    {
57	      $push: { rate_limit_hits: { timestamp: now } },
58	      $set: { last_used_at: now }
59	    }
60	  );
61	
62	  req.extensionClient = matchedClient;
63	  next();
64	}
