33	      categoryWeights[cat] = (categoryWeights[cat] || 0) + 1;
34	    }
35	    for (const tag of movie.tags || []) {
36	      tagWeights[tag] = (tagWeights[tag] || 0) + 1;
37	    }
38	  }
39	
40	  // Find movies with similar categories/tags, excluding already viewed
41	  const topCategories = Object.entries(categoryWeights).sort((a, b) => b[1] - a[1]).slice(0, 5).map(e => e[0]);
42	  const topTags = Object.entries(tagWeights).sort((a, b) => b[1] - a[1]).slice(0, 10).map(e => e[0]);
43	
44	  const recommended = await Movie.find({
45	    _id: { $nin: viewedMovieIds },
46	    deleted_at: null,
47	    is_published: true,
48	    $or: [
49	      { categories: { $in: topCategories } },
50	      { tags: { $in: topTags } }
