11	async function request(method, path, body = null, options = {}) {
12	  const token = sessionStorage.getItem('cineride_token');
13	  const headers = {};
14	
15	  if (!(body instanceof FormData)) {
16	    headers['Content-Type'] = 'application/json';
17	  }
18	
19	  if (token) {
20	    headers['Authorization'] = `Bearer ${token}`;
21	  }
22	
23	  const config = {
24	    method,
25	    headers,
26	    ...options
27	  };
28	
29	  if (body) {
30	    config.body = body instanceof FormData ? body : JSON.stringify(body);
31	  }
32	
33	  const res = await fetch(`${BASE_URL}${path}`, config);
34	
35	  if (res.status === 401) {
36	    // Read user role before clearing, to redirect to correct login portal
37	    const userStr = sessionStorage.getItem('cineride_user');
38	    let loginPath = '/login';
39	    try {
40	      const user = JSON.parse(userStr);
41	      if (user?.role) loginPath = ROLE_LOGIN_MAP[user.role] || '/login';
42	    } catch {}
43	    sessionStorage.removeItem('cineride_token');
44	    sessionStorage.removeItem('cineride_user');
45	    if (!path.includes('/auth/login')) {
46	      window.location.href = loginPath;
47	    }
48	  }
49	
50	  const data = await res.json().catch(() => ({}));
51	
52	  if (!res.ok) {
53	    const error = new Error(data.message || `Request failed with status ${res.status}`);
54	    error.code = data.code;
55	    error.status = res.status;
56	    error.details = data.details;
57	    throw error;
58	  }
