    expect(result.source).toBe('cold_start');
    expect(Array.isArray(result.movies)).toBe(true);
  });

  test('cold start includes trending and curated movies', async () => {
    const result = await recService.getColdStartRecommendations(10);
    expect(result.source).toBe('cold_start');
    expect(result.movies.length).toBeGreaterThanOrEqual(0);
  });
});

