    expect(result.source).toBe('personalized');
    expect(Array.isArray(result.movies)).toBe(true);
  });

  test('personalized excludes already-viewed movies', async () => {
    const result = await recService.getRecommendations(recUserId, 10);
    const ids = result.movies.map(m => m._id.toString());
