  test('getTrendingMovies returns movies sorted by interaction count', async () => {
    const movies = await recService.getTrendingMovies(5);
    expect(Array.isArray(movies)).toBe(true);
  });

  test('getTrendingMovies respects excludeIds', async () => {
    const movies = await recService.getTrendingMovies(5, [movieA._id]);
    const ids = movies.map(m => m._id.toString());
    expect(ids).not.toContain(movieA._id.toString());
  });
});
"}

