   200	async function retryFailedEntries() {
   201	  const maxRetries = await getConfig('ledger_max_retries', 3);
   202	  const entries = await LedgerEntry.find({
   203	    status: 'failed',
   204	    retry_count: { $lt: maxRetries },
   205	    day_closed: false,
   206	    deleted_at: null
   207	  });
   208	
   209	  let retried = 0;
   210	  for (const entry of entries) {
   211	    const backoffMs = Math.pow(4, entry.retry_count) * 1000;
   212	    const lastAttempt = entry.last_retry_at || entry.created_at;
   213	    const nextRetryAfter = new Date(lastAttempt.getTime() + backoffMs);
   214	
   215	    if (new Date() < nextRetryAfter) continue;
   216	
   217	    entry.retry_count += 1;
   218	
   219	    try {
