    if (newTotal > ride.fare_amount) {
      throw new ValidationError(
        `OVERPAY: total $${newTotal.toFixed(2)} would exceed fare $${ride.fare_amount.toFixed(2)}. ` +
        `Existing: $${existingTotal.toFixed(2)}, attempted: $${data.amount.toFixed(2)}.`
      );
    }
  }"}

