    10	export default function SearchPage() {
    11	  const { user } = useAuthStore();
    12	  const canSearchUsers = ['administrator', 'dispatcher'].includes(user?.role);
    13	  const [searchParams, setSearchParams] = useSearchParams();
    14	  const [query, setQuery] = useState(searchParams.get('q') || '');
    15	  const [results, setResults] = useState({ movies: [], content: [], users: [], total: 0 });
    16	  const [type, setType] = useState('');
    17	  const [sort, setSort] = useState('');
    18	  const [loading, setLoading] = useState(false);
    19	  const [error, setError] = useState(null);
    20	
    21	  const [suggestions, setSuggestions] = useState([]);
    22	  const [showSuggestions, setShowSuggestions] = useState(false);
    23	  const [selectedIndex, setSelectedIndex] = useState(-1);
    24	  const suggestRef = useRef(null);
    25	  const inputRef = useRef(null);
    26	
    27	  const typeRef = useRef(type);
    28	  const sortRef = useRef(sort);
    29	  typeRef.current = type;
    30	  sortRef.current = sort;
    31	
    32	  useEffect(() => {
    33	    const q = searchParams.get('q');
    34	    if (q) {
    35	      setQuery(q);
    36	      doSearch(q, typeRef.current, sortRef.current);
    37	    }
    38	  }, [searchParams]);
    39	
    40	  useEffect(() => {
    41	    function handleClickOutside(e) {
    42	      if (suggestRef.current && !suggestRef.current.contains(e.target)) {
    43	        setShowSuggestions(false);
    44	      }
    45	    }
    46	    document.addEventListener('mousedown', handleClickOutside);
    47	    return () => document.removeEventListener('mousedown', handleClickOutside);
    48	  }, []);
    49	
    50	  const suggestTimer = useRef(null);
    51	
    52	  function fetchSuggestions(q) {
    53	    clearTimeout(suggestTimer.current);
    54	    if (!q || q.trim().length < 2) {
    55	      setSuggestions([]);
    56	      setShowSuggestions(false);
    57	      return;
    58	    }
    59	    suggestTimer.current = setTimeout(async () => {
    60	      try {
    61	        const res = await api.get(`/search/suggest?q=${encodeURIComponent(q.trim())}`);
    62	        setSuggestions(res.suggestions || []);
    63	        setShowSuggestions(true);
    64	        setSelectedIndex(-1);
    65	      } catch {
    66	        setSuggestions([]);
    67	      }
    68	    }, SUGGEST_DEBOUNCE_MS);
    69	  }
    70	
    71	  function handleInputChange(e) {
    72	    const val = e.target.value;
    73	    setQuery(val);
    74	    fetchSuggestions(val);
    75	  }
    76	
    77	  function handleKeyDown(e) {
    78	    if (!showSuggestions || suggestions.length === 0) return;
    79	    if (e.key === 'ArrowDown') {
    80	      e.preventDefault();
    81	      setSelectedIndex(i => Math.min(i + 1, suggestions.length - 1));
    82	    } else if (e.key === 'ArrowUp') {
    83	      e.preventDefault();
    84	      setSelectedIndex(i => Math.max(i - 1, 0));
    85	    } else if (e.key === 'Enter' && selectedIndex >= 0) {
    86	      e.preventDefault();
    87	      selectSuggestion(suggestions[selectedIndex]);
    88	    } else if (e.key === 'Escape') {
    89	      setShowSuggestions(false);
    90	    }
    91	  }
    92	
    93	  function selectSuggestion(suggestion) {
    94	    const text = suggestion.text || suggestion;
    95	    setQuery(text);
    96	    setShowSuggestions(false);
    97	    setSuggestions([]);
    98	    setSearchParams({ q: text });
    99	    doSearch(text, type, sort);
   100	  }
   101	
   102	  async function doSearch(q, searchType, searchSort) {
   103	    if (!q || !q.trim()) return;
   104	    setLoading(true);
   105	    setError(null);
   106	    try {
   107	      const params = new URLSearchParams({ q: q.trim() });
   108	      if (searchType) params.set('type', searchType);
   109	      if (searchSort) params.set('sort', searchSort);
   110	      const res = await api.get(`/search?${params}`);
   111	      setResults(res);
   112	    } catch (err) {
   113	      setError(err.message || 'Search failed. Please try again.');
   114	      setResults({ movies: [], content: [], users: [], total: 0 });
   115	    }
   116	    setLoading(false);
   117	  }
   118	
   119	  const handleSearch = (e) => {
   120	    e.preventDefault();
   121	    setShowSuggestions(false);
   122	    setSearchParams({ q: query });
   123	    doSearch(query, type, sort);
   124	  };
   125	
   126	  function handleTypeChange(newType) {
   127	    setType(newType);
   128	    if (query) doSearch(query, newType, sort);
   129	  }
   130	
   131	  function handleSortChange(newSort) {
   132	    setSort(newSort);
   133	    if (query) doSearch(query, type, newSort);
   134	  }
   135	
   136	  return (
   137	    <div className="space-y-4">
   138	      <h1 className="text-xl font-bold">Search</h1>
   139	
   140	      <form onSubmit={handleSearch} className="flex flex-col sm:flex-row gap-2">
   141	        <div className="relative flex-1" ref={suggestRef}>
   142	          <input
   143	            ref={inputRef}
   144	            className="input w-full"
   145	            value={query}
