   161	            >
   162	              {suggestions.map((s, i) => (
   163	                <li
   164	                  key={s._id || s.text || i}
   165	                  role="option"
   166	                  aria-selected={i === selectedIndex}
   167	                  className={`px-4 py-2 cursor-pointer text-sm ${
   168	                    i === selectedIndex
   169	                      ? 'bg-blue-100 dark:bg-blue-900'
