   171	                  }`}
   172	                  onMouseDown={() => selectSuggestion(s)}
   173	                >
   174	                  <span>{s.text}</span>
   175	                  {s.type && (
   176	                    <span className="ml-2 text-xs text-gray-400">{s.type}</span>
   177	                  )}
   178	                </li>
   179	              ))}
   180	            </ul>
   181	          )}
   182	        </div>
   183	        <button type="submit" className="btn-primary w-full sm:w-auto">Search</button>
   184	      </form>
   185	
   186	      <div className="flex flex-wrap gap-2">
   187	        {['', 'movie', 'content', ...(canSearchUsers ? ['user'] : [])].map(t => (
   188	          <button key={t} className={`btn-sm ${type === t ? 'btn-primary' : 'btn-outline'}`}
   189	            onClick={() => handleTypeChange(t)}>
