   191	          </button>
   192	        ))}
   193	        <select className="input w-full sm:w-36 h-8 text-xs" value={sort}
   194	          onChange={e => handleSortChange(e.target.value)}>
   195	          <option value="">Relevance</option>
   196	          <option value="popularity">Popularity</option>
   197	          <option value="newest">Newest</option>
   198	          <option value="rating">Rating</option>
   199	        </select>
   200	      </div>
   201	
   202	      {loading && <div className="text-center text-muted-foreground py-8">Searching...</div>}
   203	
   204	      {error && (
   205	        <div className="bg-red-50 dark:bg-red-950/20 border border-red-200 dark:border-red-800 rounded-lg p-4 text-sm text-red-700 dark:text-red-300">
   206	          {error}
   207	        </div>
   208	      )}
   209	
   210	      {!loading && !error && results.total > 0 && (
   211	        <div className="space-y-6">
   212	          <p className="text-sm text-muted-foreground">{results.total} results found</p>
   213	
   214	          {results.movies?.length > 0 && (
   215	            <div>
   216	              <h2 className="font-semibold mb-2">Movies ({results.movies.length})</h2>
