   225	                    <div className="text-xs text-muted-foreground mt-1">{formatDate(m.release_date)}</div>
   226	                  </div>
   227	                ))}
   228	              </div>
   229	            </div>
   230	          )}
   231	
   232	          {results.content?.length > 0 && (
   233	            <div>
   234	              <h2 className="font-semibold mb-2">Content ({results.content.length})</h2>
