   240	                      <p className="text-xs text-muted-foreground capitalize">{c.content_type} · {c.author?.display_name}</p>
   241	                    </div>
   242	                    <StatusBadge status={c.status} />
   243	                  </div>
   244	                ))}
   245	              </div>
   246	            </div>
