   266	
   267	      {!loading && !error && results.total === 0 && query && (
   268	        <div className="text-center text-muted-foreground py-8">
   269	          No results found for "{query}". Try a different search term.
   270	        </div>
   271	      )}
   272	    </div>
   273	  );
   274	}
